PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?club ?appearanceCount WHERE {
  VALUES ?club {
    wd:Q3044572 wd:Q2521385 wd:Q2272176
  }
  ?club wdt:P1387 ?appearanceCount .
}
ORDER BY ASC(?appearanceCount)

